/* Charm Bug Review Tool styles */

/* Severity badges */
.severity-badge {
    display: inline-block;
    padding: 0.1rem 0.4rem;
    border-radius: 4px;
    font-size: 0.8rem;
    font-weight: bold;
    color: white;
}
.severity-critical { background: #dc2626; }
.severity-high { background: #ea580c; }
.severity-medium { background: #ca8a04; }
.severity-low { background: #2563eb; }

/* Status indicators */
.status-pending { color: #9ca3af; font-size: 1.2rem; }
.status-reviewed { color: #16a34a; font-size: 1.2rem; font-weight: bold; }
.status-fp { color: #dc2626; font-size: 1.2rem; font-weight: bold; }

/* Two-panel layout */
.two-panel {
    display: grid;
    grid-template-columns: 35% 65%;
    gap: 1rem;
    min-height: 70vh;
}

.findings-list-panel {
    overflow-y: auto;
    max-height: 80vh;
    border-right: 1px solid var(--pico-muted-border-color);
    padding-right: 1rem;
}

.detail-panel {
    overflow-y: auto;
    max-height: 80vh;
    padding-left: 1rem;
}

.empty-detail {
    text-align: center;
    color: var(--pico-muted-color);
    margin-top: 4rem;
}

/* Finding rows */
.findings-table tbody tr {
    transition: background-color 0.15s;
}
.findings-table tbody tr:hover {
    background-color: var(--pico-primary-focus);
}
.finding-row.active {
    background-color: var(--pico-primary-focus) !important;
    border-left: 3px solid var(--pico-primary);
}

/* Code blocks */
.code-block {
    background: #1e1e2e;
    color: #cdd6f4;
    border-radius: 8px;
    padding: 1rem;
    overflow-x: auto;
    font-size: 0.85rem;
    margin: 0.5rem 0 1rem 0;
}
.code-block code {
    background: transparent;
    color: inherit;
}
.code-block .highlight {
    background: transparent;
}
.code-block pre {
    margin: 0;
    background: transparent;
    color: #cdd6f4;
}

/* Pygments monokai-ish overrides */
.highlight .k, .highlight .kn, .highlight .kd { color: #cba6f7; }
.highlight .s, .highlight .s1, .highlight .s2 { color: #a6e3a1; }
.highlight .n { color: #cdd6f4; }
.highlight .nf, .highlight .nc { color: #89b4fa; }
.highlight .c, .highlight .c1, .highlight .cm { color: #6c7086; font-style: italic; }
.highlight .o, .highlight .p { color: #94e2d5; }
.highlight .mi, .highlight .mf { color: #fab387; }
.highlight .nb { color: #f9e2af; }
.highlight .bp { color: #f9e2af; }
.highlight .nn { color: #89b4fa; }

/* Stats bar */
.stats-bar {
    margin-bottom: 1rem;
}

/* Filters */
.filters {
    margin-bottom: 1rem;
}
.filters select {
    margin-bottom: 0;
    padding: 0.3rem 0.5rem;
    font-size: 0.85rem;
}

/* Keyboard shortcut hints on list */
.kbd-help {
    display: block;
    text-align: right;
    color: var(--pico-muted-color);
    margin-bottom: 0.3rem;
}
.kbd-help kbd {
    display: inline-block;
    padding: 0.1rem 0.3rem;
    font-size: 0.7rem;
    background: var(--pico-muted-border-color);
    border: 1px solid var(--pico-muted-color);
    border-radius: 3px;
    margin: 0 0.1rem;
}

/* Keyboard shortcut hints on buttons */
button kbd, a[role="button"] kbd {
    display: inline-block;
    padding: 0.1rem 0.35rem;
    font-size: 0.7rem;
    font-family: inherit;
    background: rgba(255, 255, 255, 0.15);
    border: 1px solid rgba(255, 255, 255, 0.25);
    border-radius: 3px;
    margin-left: 0.3rem;
    vertical-align: middle;
    line-height: 1;
}

/* Review actions */
.review-actions {
    margin-top: 0.5rem;
}
.review-actions textarea {
    margin-top: 0.5rem;
}

/* Responsive */
@media (max-width: 768px) {
    .two-panel {
        grid-template-columns: 1fr;
    }
    .findings-list-panel {
        max-height: 40vh;
        border-right: none;
        border-bottom: 1px solid var(--pico-muted-border-color);
        padding-right: 0;
        padding-bottom: 1rem;
    }
    .detail-panel {
        padding-left: 0;
    }
}

